26	const componentGroupPremium = (count: number): number =>
27	  count === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PREMIUM
29	    : count * COMPONENT_BASE_PREMIUM;
30	
31	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
32	
33	const mainItemPremium = (item: Item): number => {
34	  const base = BASE_PREMIUM_BY_TYPE[item.type];
35	  let total = base;
36	  if (item.cursed) {
37	    total += base * CURSE_SURCHARGE_RATE + base * FIRST_INSURANCE_RATE;
38	  }
39	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
40	    total += base * HIGH_ENCHANTMENT_RATE;
41	  }
42	  return total;
43	};
44	
45	const countByType = (items: Item[]): Map<string, number> =>
46	  items.reduce(
47	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
48	    new Map<string, number>(),
49	  );
50	
51	const sumComponentPremiums = (components: Item[]): number =>
52	  [...countByType(components).values()]
53	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
54	
55	const sumItemPremiums = (items: Item[]): number => {
56	  const mains = items.filter(isMainItem);
57	  const components = items.filter((i) => !isMainItem(i));
58	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item), 0);
59	  return mainsSum + sumComponentPremiums(components);
60	};
61	
62	const quotePremiumFor = (step: Step): { premium: number } => ({
63	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
64	});
65	
66	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
67	  results: scenario.steps.map(quotePremiumFor),
68	});
